import React, { useState, useEffect } from 'react';

const App = () => {
  const [data, setData] = useState({});
  const [form, setForm] = useState({
    uid: '',
    username: '',
    languagePref: '',
    userImg: ''
  });

  useEffect(() => {
    fetch('/data')
      .then(response => {
        if (!response.ok) {
          throw new Error('Network response was not ok');
        }
        return response.json();
      })
      .then(data => {
        console.log('Data fetched:', data);
        setData(data);
      })
      .catch(error => console.error('Error fetching data:', error));
  }, []);

  const handleChange = (e) => {
    setForm({
      ...form,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    fetch('/data', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify(form)
    })
    .then(response => {
      if (!response.ok) {
        throw new Error('Network response was not ok');
      }
      return response.text();
    })
    .then(message => {
      console.log(message);
      // Reset form
      setForm({
        uid: '',
        username: '',
        languagePref: '',
        userImg: ''
      });
      // Fetch the updated data
      return fetch('/data');
    })
    .then(response => response.json())
    .then(updatedData => setData(updatedData))
    .catch(error => console.error('Error adding user:', error));
  };

  return (
    <div>
      <h1>Admin Page</h1>
      {Object.keys(data).length ? (
        <table>
          <thead>
            <tr>
              <th>UID</th>
              <th>Username</th>
              <th>Language Preference</th>
              <th>User Image</th>
            </tr>
          </thead>
          <tbody>
            {Object.keys(data).map(key => (
              <tr key={key}>
                <td>{key}</td>
                <td>{data[key].username}</td>
                <td>{data[key].languagePref}</td>
                <td><img src={data[key].userImg} alt={data[key].username} width="50" /></td>
              </tr>
            ))}
          </tbody>
        </table>
      ) : (
        <p>Loading...</p>
      )}
      <h2>Add User</h2>
      <form onSubmit={handleSubmit}>
        <input type="text" name="uid" placeholder="UID" value={form.uid} onChange={handleChange} required />
        <input type="text" name="username" placeholder="Username" value={form.username} onChange={handleChange} required />
        <input type="text" name="languagePref" placeholder="Language Preference" value={form.languagePref} onChange={handleChange} required />
        <input type="text" name="userImg" placeholder="User Image URL" value={form.userImg} onChange={handleChange} required />
        <button type="submit">Add User</button>
      </form>
    </div>
  );
};

export default App;
